package com.chaobo.scm.supplier.interfaces.web;
import com.chaobo.scm.common.api.ApiResponse;import com.chaobo.scm.supplier.application.integration.InboundEventReplayApplicationService;import com.chaobo.scm.supplier.application.operations.*;import com.chaobo.scm.supplier.infrastructure.security.CommandContextFactory;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.security.core.*;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.security.oauth2.jwt.Jwt;import org.springframework.web.bind.annotation.*;import java.math.BigDecimal;import java.time.LocalDate;import java.util.List;
@RestController @RequestMapping("/api/supplier/v1/operations")public class SupplierOperationsController{private final SupplierOperationsApplicationService service;private final InboundEventReplayApplicationService inboundReplay;private final CommandContextFactory contexts;public SupplierOperationsController(SupplierOperationsApplicationService service,InboundEventReplayApplicationService inboundReplay,CommandContextFactory contexts){this.service=service;this.inboundReplay=inboundReplay;this.contexts=contexts;}@GetMapping("/work-items")public ApiResponse<List<OperationViews.WorkItem>> work(@RequestParam(required=false)Long supplierId,@RequestParam(required=false)Integer status,@RequestParam(defaultValue="1")int pageNo,@RequestParam(defaultValue="20")int pageSize,@AuthenticationPrincipal Jwt jwt,HttpServletRequest request){return ok(service.workItems(supplierId,scope(jwt),status,pageNo,pageSize),request);}@PostMapping("/work-items/{id}/process")public ApiResponse<Void> processWork(@PathVariable long id,@Valid @RequestBody Process body,HttpServletRequest request,Authentication authentication){service.processWork(id,body.version(),body.close(),contexts.create(request,authentication));return ok(null,request);}@GetMapping("/warnings")public ApiResponse<List<OperationViews.Warning>> warnings(@RequestParam(required=false)Long supplierId,@RequestParam(required=false)Integer status,@RequestParam(defaultValue="1")int pageNo,@RequestParam(defaultValue="20")int pageSize,@AuthenticationPrincipal Jwt jwt,HttpServletRequest request){return ok(service.warnings(supplierId,scope(jwt),status,pageNo,pageSize),request);}@PostMapping("/warnings/{id}/process")public ApiResponse<Void> processWarning(@PathVariable long id,@Valid @RequestBody Process body,HttpServletRequest request,Authentication authentication){service.processWarning(id,body.version(),body.close(),contexts.create(request,authentication));return ok(null,request);}@GetMapping("/failed-events")public ApiResponse<List<OperationViews.FailedEvent>> failed(HttpServletRequest request){return ok(service.failedEvents(),request);}@PostMapping("/failed-events/{id}/replay")public ApiResponse<Void> replay(@PathVariable long id,@Valid @RequestBody Replay body,HttpServletRequest request,Authentication authentication){var context=contexts.create(request,authentication);if("INBOUND".equals(body.direction()))inboundReplay.replay(id,body.reason(),context);else service.replay(id,body.direction(),body.reason(),context);return ok(null,request);}@PostMapping("/data-reconciliations")public ApiResponse<Void> reconcile(@Valid @RequestBody Reconcile body,HttpServletRequest request,Authentication authentication){service.reconcile(body.type(),body.targetSystem(),body.businessDate(),body.remoteCount(),body.remoteAmount(),contexts.create(request,authentication));return ok(null,request);}@GetMapping("/data-reconciliations")public ApiResponse<List<OperationViews.Reconciliation>> reconciliations(HttpServletRequest request){return ok(service.reconciliations(),request);}@GetMapping("/dashboard")public ApiResponse<OperationViews.Dashboard> dashboard(HttpServletRequest request){return ok(service.dashboard(),request);}private<T>ApiResponse<T>ok(T value,HttpServletRequest request){return ApiResponse.success(value,request.getHeader("X-Request-Id"),request.getHeader("X-Trace-Id"));}private Long scope(Jwt jwt){Number value=jwt.hasClaim("supplier_id")?jwt.getClaim("supplier_id"):null;return value==null?null:value.longValue();}public record Process(@PositiveOrZero int version,boolean close){}public record Replay(@Pattern(regexp="INBOUND|OUTBOUND")String direction,@NotBlank String reason){}public record Reconcile(@Pattern(regexp="ASN|SUPPLIER_RETURN|STATEMENT")String type,@NotBlank String targetSystem,@NotNull LocalDate businessDate,@PositiveOrZero long remoteCount,BigDecimal remoteAmount){} }
